# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_hyperbolic.test_cosh_positive","kind":"function","src_hash":"4d8669a04ab0bb63","in":{"base":"Any"},"out":{"base":"Any","pred":"cosh(k, evaluate=False).is_positive is True and cosh(k + 2 * n * pi * I, evaluate=False).is_positive is True and cosh(I * pi / 4, evaluate=False).is_positive is True and cosh(3 * I * pi / 4, evaluate=False).is_positive is False"},"spec":{"lhs":"test_cosh_positive()","rhs":"test_cosh_positive produces the expected output","over":{"base":"Any"},"name":"test_cosh_positive_correct"},"guarantee":"test_cosh_positive produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_hyperbolic.test_cosh_positive_correct","statement":"Path(test_cosh_positive(x), test_cosh_positive produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"25696d49afa3a420"}
def test_cosh_positive():
    # See issue 11721
    # cosh(x) is positive for real values of x
    k = symbols('k', real=True)
    n = symbols('n', integer=True)

    assert cosh(k, evaluate=False).is_positive is True
    assert cosh(k + 2*n*pi*I, evaluate=False).is_positive is True
    assert cosh(I*pi/4, evaluate=False).is_positive is True
    assert cosh(3*I*pi/4, evaluate=False).is_positive is False

