# @cctt_verify {"v":2,"sym":"sympy.functions.elementary.tests.test_hyperbolic.test_issue_25847","kind":"function","src_hash":"78eb04e6aa6b2572","in":{"base":"Any"},"out":{"base":"Any","pred":"atanh(sin(x) / x).as_leading_term(x) == atanh(sin(x) / x) and asinh(sin(x) / x).as_leading_term(x) == log(1 + sqrt(2)) and acosh(sin(x) / x).as_leading_term(x) == 0 and acoth(sin(x) / x).as_leading_term(x) == acoth(sin(x) / x) and asech(sinh(x) / x).as_leading_term(x) == 0 and acsch(sin(x) / x).as_leading_term(x) == log(1 + sqrt(2))"},"spec":{"lhs":"test_issue_25847()","rhs":"test_issue_25847 produces the expected output","over":{"base":"Any"},"name":"test_issue_25847_correct"},"guarantee":"test_issue_25847 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.functions.elementary.tests.test_hyperbolic.test_issue_25847_correct","statement":"Path(test_issue_25847(x), test_issue_25847 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"84f21694b2048666"}
def test_issue_25847():
    x = Symbol('x')

    #atanh
    assert atanh(sin(x)/x).as_leading_term(x) == atanh(sin(x)/x)
    raises(PoleError, lambda: atanh(exp(1/x)).as_leading_term(x))

    #asinh
    assert asinh(sin(x)/x).as_leading_term(x) == log(1 + sqrt(2))
    raises(PoleError, lambda: asinh(exp(1/x)).as_leading_term(x))

    #acosh
    assert acosh(sin(x)/x).as_leading_term(x) == 0
    raises(PoleError, lambda: acosh(exp(1/x)).as_leading_term(x))

    #acoth
    assert acoth(sin(x)/x).as_leading_term(x) == acoth(sin(x)/x)
    raises(PoleError, lambda: acoth(exp(1/x)).as_leading_term(x))

    #asech
    assert asech(sinh(x)/x).as_leading_term(x) == 0
    raises(PoleError, lambda: asech(exp(1/x)).as_leading_term(x))

    #acsch
    assert acsch(sin(x)/x).as_leading_term(x) == log(1 + sqrt(2))
    raises(PoleError, lambda: acsch(exp(1/x)).as_leading_term(x))


